def d(l):
    u, v = l
    return (v[0]-u[0], v[1]-u[1], v[2]-u[2])

def perp(l1, l2):
    return sum(a*b for a, b in zip(d(l1), d(l2))) == 0

def intersect(l1, l2):
    u1, v1 = l1
    u2, v2 = l2
    if u1 == u2 or u1 == v2 or v1 == u2 or v1 == v2:
        return True
    w = (u2[0]-u1[0], u2[1]-u1[1], u2[2]-u1[2])
