          d(l2)[2]*w[0] - d(l2)[0]*w[2],
          d(l2)[0]*w[1] - d(l2)[1]*w[0])
    return sum(a*b for a, b in zip(d(l1), cp)) == 0

def length(l):
    dd = d(l)
    return dd[0]**2 + dd[1]**2 + dd[2]**2

